// class, public, static, void, int, if, else, for, while...

public class OperatorDemo {
    public static void main(String[] args) {
        int result = 10 + 20 * 3 - 40 / 5;
        System.out.println("Result: " + result); // 输出: 62

        // 逻辑运算符示例
        boolean flag = (3 > 2) && (5 < 10) || (2 == 2);
        System.out.println("Flag: " + flag); // 输出: true
    }
}

public class PrecisionDemo {
    public static void main(String[] args) {
        // 整数除法
        System.out.println(10 / 3); // 3

        // 浮点数除法
        System.out.println(10.0 / 3); // 3.3333333333333335

        // 精度误差示例
        System.out.println(0.1 + 0.2); // 0.30000000000000004

        // 正确比较方式
        double a = 0.1 + 0.2;
        System.out.println(a == 0.3); // false
        System.out.println(Math.abs(a - 0.3) < 0.0001); // true
    }
}

