arrDynamic[0] = 10;

int[] data = {5, 2, 9, 1, 6};

// 1. 安全遍历
for (int i = 0; i < data.length; i++) {
    System.out.print(data[i] + " ");
}

// 2. 冒泡排序实现
for (int i = 0; i < data.length - 1; i++) {
    for (int j = 0; j < data.length - 1 - i; j++) {
        if (data[j] > data[j + 1]) {
            int temp = data[j];
            data[j] = data[j + 1];
            data[j + 1] = temp;
        }
    }
}

